module top_module (
    input wire clk,
    input wire reset,
    input wire d,
    output reg q
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= 1'b0;
        else
            q <= d;
    end

  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        q <= 1'b1;
      end
    end
  end

endmodule
